#[derive(Debug, Clone, Copy)]
pub struct MaterialPreset {
    pub abbrev: &'static str,
    pub name: &'static str,
    pub bulk_density: f64,
    pub max_moisture_pct: f64,
    pub temp_min: u16,
    pub temp_max: u16,
    pub drying_time_min: f64,
    pub drying_time_max: f64,
    /// Multiply by throughput [kg/h] to get required air volume [m3/h].
    pub specific_air_volume: f64,
}

impl MaterialPreset {
    pub fn recommended_temp(&self) -> u16 {
        ((self.temp_min as u32 + self.temp_max as u32) / 2) as u16
    }
}

